import org.junit.jupiter.api.Tag;
import org.junit.jupiter.api.BeforeEach;
import static org.junit.jupiter.api.Assertions.*;

import phd.distributed.api.A;
import phd.distributed.api.DistAlgorithm;

@Tag("unit")
class ExecutionerTest {

    private DistAlgorithm algorithm;
    private Executioner executioner;

    @BeforeEach
    void setUp() {
        algorithm = new A("java.util.concurrent.ConcurrentLinkedQueue");
        executioner = new Executioner(2, 100, algorithm, "queue");
    }

    @Test
    @Tag("fast")
    void testExecutionerCreation() {
        assertNotNull(executioner);
    }

    @Test
    @Tag("fast")
    void testExecutionerCreationWithDifferentProcessCounts() {
        Executioner exec1 = new Executioner(1, 100, algorithm, "queue");
        Executioner exec4 = new Executioner(4, 100, algorithm, "queue");
        Executioner exec8 = new Executioner(8, 100, algorithm, "queue");

        assertNotNull(exec1);
        assertNotNull(exec4);
        assertNotNull(exec8);
    }

    @Test
    void testTaskProducersCompletes() {
        try {
            executioner.taskProducers();
        } catch (Exception e) {
            fail("Should not throw exception: " + e.getMessage());
        }
    }

    @Test
    void testSequentialExecution() {
        try {
            executioner.taskProducers();
            boolean result = executioner.taskVerifiers();
            // Result can be true or false, just verify it completes
        } catch (Exception e) {
            fail("Should not throw exception: " + e.getMessage());
        }
    }

    @Test
    void testWithDifferentAlgorithms() {
        DistAlgorithm queueAlgorithm = new A("java.util.concurrent.LinkedBlockingQueue");
        Executioner queueExecutioner = new Executioner(2, 50, queueAlgorithm, "queue");

        try {
            queueExecutioner.taskProducers();
            queueExecutioner.taskVerifiers();
        } catch (Exception e) {
            fail("Should not throw exception: " + e.getMessage());
        }
    }
}

